import React, { useState } from "react";
import Login from "../Login/Login";
import Register from "../Register/Register";
import LoginError from "../LoginError/LoginError";
import RegisterError from "../RegisterError/RegisterError";
import styles from "./AuthModal.module.css";

interface AuthModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const AuthModal: React.FC<AuthModalProps> = ({ isOpen, onClose }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [showLoginError, setShowLoginError] = useState(false);
  const [showRegisterError, setShowRegisterError] = useState(false);

  if (!isOpen) return null;

  const handleSwitchToRegister = () => {
    setIsLogin(false);
    setShowLoginError(false);
    setShowRegisterError(false);
  };

  const handleSwitchToLogin = () => {
    setIsLogin(true);
    setShowLoginError(false);
    setShowRegisterError(false);
  };

  // Показываем LoginError
  if (isLogin && showLoginError) {
    return (
      <div className={styles.overlay}>
        <LoginError
          onSwitchToRegister={handleSwitchToRegister}
          onClose={onClose}
        />
      </div>
    );
  }

  // Показываем RegisterError
  if (!isLogin && showRegisterError) {
    return (
      <div className={styles.overlay}>
        <RegisterError
          onSwitchToLogin={handleSwitchToLogin}
          onClose={onClose}
        />
      </div>
    );
  }

  // Показываем Login (без ошибки)
  if (isLogin) {
    return (
      <div className={styles.overlay}>
        <Login onSwitchToRegister={handleSwitchToRegister} onClose={onClose} />
      </div>
    );
  }

  // Показываем Register (без ошибки)
  return (
    <div className={styles.overlay}>
      <Register onSwitchToLogin={handleSwitchToLogin} onClose={onClose} />
    </div>
  );
};

export default AuthModal;
